def second_largest(nums):
    if len(nums) < 2:
        return None  # not enough elements

    largest = None
    second = None

    for x in nums:
        if largest is None or x > largest:
            second = largest
            largest = x
        elif x != largest and (second is None or x > second):
            second = x

    return second  # None if there is no second distinct largest
